    fn list_models_with_reasoning_variants_generates_entries() {
        let mut reg = ProviderRegistry::empty();
        reg.register(
            ModelInfo {
                id: "claude-opus-4-5-20251101".into(),
                provider: "anthropic".into(),
                display_name: "Claude Opus 4.5".into(),
